const base64 = $json.body.fileBase64;
const fileName = $json.body.fileName || "resume.pdf";

if (!base64) {
  throw new Error("fileBase64 is missing");
}

const buffer = Buffer.from(base64, "base64");

// Detect file type
let mimeType = "application/pdf";

if (fileName.toLowerCase().endsWith(".txt")) {
  mimeType = "text/plain";
}

return [{
  binary: {
    data: {
      data: buffer,
      mimeType: mimeType,
      fileName: fileName
    }
  }
}];

const allResults = $input.all().map(item => item.json);

// sort highest match first
allResults.sort((a, b) => b.match_percentage - a.match_percentage);

// take top 4
const top4 = allResults.slice(0, 4);

return [{
  json: {
    total_jobs_analyzed: allResults.length,
    top_matches: top4
  }
}];

const stopWords = ["with","and","the","for","using","looking","experience","knowledge"];

const resume = $json.resumeText.toLowerCase();
const jobTitle = $json.title;
const jobDescription = $json.description.toLowerCase();

const keywords = jobDescription
  .replace(/[^a-zA-Z0-9 ]/g, "")
  .split(" ")
  .filter(word => word.length > 3 && !stopWords.includes(word));

const uniqueKeywords = [...new Set(keywords)];

let matched = [];
let missing = [];

uniqueKeywords.forEach(keyword => {
  if (resume.includes(keyword)) {
    matched.push(keyword);
  } else {
    missing.push(keyword);
  }
});

let percentage = Math.round((matched.length / uniqueKeywords.length) * 100);

if (percentage > 95) percentage = 95;
if (percentage < 10) percentage = 10;

let assessment = "Moderate fit";

if (percentage >= 75) {
  assessment = "Strong candidate - recommend interview";
} else if (percentage >= 50) {
  assessment = "Potential fit - recommend phone screen";
} else {
  assessment = "Limited match - consider skill improvement";
}

return {
    job_title: jobTitle,
    match_percentage: percentage,
    required_skills_present: matched.slice(0, 6),
    skill_gaps: missing.slice(0, 6),
    overall_assessment: assessment
  };

const resumeText = $json.resumeText;

const jobs = [
  {"title":"Machine Learning Engineer","description":"Python machine learning TensorFlow PyTorch pandas numpy modeling"},
  {"title":"Software Engineer","description":"JavaScript Python REST APIs microservices cloud Git testing"},
  {"title":"Frontend Developer","description":"HTML CSS JavaScript React Vue UI UX responsive design"},
  {"title":"Backend Developer","description":"Node.js Express REST APIs authentication MongoDB SQL caching"},
  {"title":"Data Analyst","description":"SQL Excel PowerBI Tableau statistics reporting visualization"},
  {"title":"DevOps Engineer","description":"Docker Kubernetes CI CD Jenkins AWS Linux scripting"},
  {"title":"Cybersecurity Analyst","description":"network security firewalls encryption penetration testing SIEM"},
  {"title":"Cloud Engineer","description":"AWS Azure GCP cloud infrastructure Terraform deployment"},
  {"title":"Full Stack Developer","description":"React Node MongoDB APIs frontend backend integration"},
  {"title":"AI Engineer","description":"NLP transformers deep learning LLM training experimentation"},
  {"title":"Mobile Developer","description":"Flutter React Native Android iOS mobile UI development"},
  {"title":"QA Engineer","description":"manual testing automation Selenium Cypress debugging"},
  {"title":"Database Administrator","description":"SQL indexing performance tuning backup recovery"},
  {"title":"System Engineer","description":"Linux networking troubleshooting monitoring configuration"},
  {"title":"UI Designer","description":"Figma Adobe XD wireframes prototyping design systems"},
  {"title":"Product Manager","description":"Agile Scrum roadmap planning stakeholder communication"},
  {"title":"Business Analyst","description":"requirements documentation process analysis UML stakeholder"},
